"use client";

import React, { useRef, useEffect, useState, useLayoutEffect } from "react";
import { motion, AnimatePresence } from "motion/react";
import {
  Bell,
  BookOpen,
  Settings,
  LayoutDashboard,
  Shield,
  X,
  Check,
  AlertCircle,
  ArrowRight,
  LucideIcon,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";

// ─── Types ────────────────────────────────────────────────────────────────────

interface DockItem {
  id: string;
  icon: LucideIcon;
  label: string;
  badge?: number;
}

interface PanelConfig {
  title: string;
  content: React.ReactNode;
  badge?: number;
  viewAllLabel?: string;
}

// ─── Shared Variants ──────────────────────────────────────────────────────────

const containerVariants = {
  hidden: (dir: number) => ({ opacity: 0, x: dir * 24 }),
  visible: {
    opacity: 1,
    x: 0,
    transition: { duration: 0.2, ease: "easeOut", staggerChildren: 0.07 },
  },
};

const itemVariants = {
  hidden: { opacity: 0, y: 6 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.2, ease: "easeOut" } },
};

// ─── PanelItem ────────────────────────────────────────────────────────────────

const PanelItem = ({ className, children }: { className?: string; children: React.ReactNode }) => (
  <motion.div variants={itemVariants} className={cn(className)}>
    {children}
  </motion.div>
);

// ─── Dock Icon ────────────────────────────────────────────────────────────────

interface AppleDockIconProps {
  className?: string;
  children?: React.ReactNode;
  onClick?: () => void;
  isActive?: boolean;
}

const AppleDockIcon = ({ className, children, onClick, isActive }: AppleDockIconProps) => (
  <div
    className={cn(
      "relative flex h-10 w-10 cursor-pointer items-center justify-center rounded-full transition-colors hover:bg-muted/80",
      className,
    )}
    onClick={onClick}
  >
    {isActive && (
      <motion.div
        layoutId="dock-active-bg"
        className="absolute inset-0 rounded-full bg-muted"
        transition={{ type: "spring", stiffness: 400, damping: 30 }}
      />
    )}
    <span className="relative z-10">{children}</span>
  </div>
);

// ─── Panel Contents ───────────────────────────────────────────────────────────

const NotificationsContent = () => {
  const items = [
    { title: "New comment on your post", time: "2m ago", unread: true },
    { title: "Your export is ready to download", time: "1h ago", unread: true },
    { title: "Team member joined your workspace", time: "3h ago", unread: false },
  ];
  return (
    <div className="flex flex-col gap-1">
      {items.map((item, i) => (
        <PanelItem
          key={i}
          className="flex cursor-pointer items-start gap-3 rounded-lg p-2 transition-colors hover:bg-muted"
        >
          <span
            className={cn(
              "mt-1.5 h-2 w-2 shrink-0 rounded-full",
              item.unread ? "bg-blue-500" : "bg-transparent",
            )}
          />
          <div className="flex-1">
            <p className="text-sm leading-snug">{item.title}</p>
            <p className="mt-0.5 text-xs text-muted-foreground">{item.time}</p>
          </div>
        </PanelItem>
      ))}
      <PanelItem className="mt-1">
        <Button variant="ghost" size="sm" className="w-full text-xs cursor-pointer">
          Mark all as read
        </Button>
      </PanelItem>
    </div>
  );
};

const ChangelogContent = () => {
  const items = [
    { version: "v2.4.0", date: "Today", note: "New dashboard layout & performance improvements" },
    { version: "v2.3.1", date: "Yesterday", note: "Bug fixes for mobile navigation" },
    { version: "v2.3.0", date: "3 days ago", note: "Added dark mode support across all panels" },
  ];
  return (
    <div className="flex flex-col">
      {items.map((item, i) => (
        <PanelItem key={i} className="flex gap-3">
          <div className="flex flex-col items-center">
            <span className="mt-1.5 h-2 w-2 shrink-0 rounded-full bg-foreground" />
            {i < items.length - 1 && <span className="mt-1 w-px flex-1 bg-border" />}
          </div>
          <div className="pb-4">
            <div className="flex items-center gap-2">
              <Badge variant="outline" className="h-5 text-xs">{item.version}</Badge>
              <span className="text-xs text-muted-foreground">{item.date}</span>
            </div>
            <p className="mt-1 text-sm text-muted-foreground">{item.note}</p>
          </div>
        </PanelItem>
      ))}
    </div>
  );
};

const DashboardContent = () => {
  const stats = [
    { label: "Total Users", value: "12,482", change: "+12%" },
    { label: "Revenue", value: "$48.2K", change: "+8%" },
    { label: "Active Now", value: "342", change: "+3%" },
    { label: "Uptime", value: "99.9%", change: "stable" },
  ];
  return (
    <div className="grid grid-cols-2 gap-2">
      {stats.map((s, i) => (
        <PanelItem key={i} className="rounded-lg bg-muted p-3">
          <p className="text-xs text-muted-foreground">{s.label}</p>
          <p className="mt-0.5 text-base font-semibold">{s.value}</p>
          <p className="mt-0.5 text-xs text-teal-400">{s.change}</p>
        </PanelItem>
      ))}
    </div>
  );
};

const SettingsContent = () => {
  const [states, setStates] = useState([true, false, true]);
  const items = ["Email notifications", "Two-factor auth", "Public profile"];
  return (
    <div className="flex flex-col gap-3">
      {items.map((label, i) => (
        <PanelItem key={i} className="flex items-center justify-between">
          <span className="text-sm">{label}</span>
          <Switch
            checked={states[i]}
            onCheckedChange={(v) =>
              setStates((prev) => prev.map((s, idx) => (idx === i ? v : s)))
            }
            className={'cursor-pointer'}
          />
        </PanelItem>
      ))}
      <PanelItem className="mt-1">
        <Button variant="outline" size="sm" className="w-full cursor-pointer">
          Advanced Settings
        </Button>
      </PanelItem>
    </div>
  );
};

const SecurityContent = () => {
  const items = [
    { label: "Password", status: "Strong", ok: true },
    { label: "2FA", status: "Not enabled", ok: false },
    { label: "Last login", status: "2 hours ago", ok: true },
    { label: "Active sessions", status: "1 device", ok: true },
  ];
  return (
    <div className="flex flex-col divide-y divide-border">
      {items.map((item, i) => (
        <PanelItem key={i} className="flex items-center justify-between py-2">
          <span className="text-sm">{item.label}</span>
          <div className="flex items-center gap-1.5">
            {item.ok ? (
              <Check className="h-3.5 w-3.5 text-teal-400" />
            ) : (
              <AlertCircle className="h-3.5 w-3.5 text-orange-400" />
            )}
            <span className={cn("text-xs", item.ok ? "text-muted-foreground" : "text-orange-400")}>
              {item.status}
            </span>
          </div>
        </PanelItem>
      ))}
    </div>
  );
};

// ─── Panel Config ─────────────────────────────────────────────────────────────

const panels: Record<string, PanelConfig> = {
  notifications: {
    title: "Notifications",
    badge: 2,
    content: <NotificationsContent />,
    viewAllLabel: "View all notifications",
  },
  changelog: {
    title: "What's New",
    content: <ChangelogContent />,
    viewAllLabel: "Full changelog",
  },
  dashboard: {
    title: "Dashboard",
    content: <DashboardContent />,
    viewAllLabel: "Open dashboard",
  },
  settings: {
    title: "Settings",
    content: <SettingsContent />,
  },
  security: {
    title: "Security",
    content: <SecurityContent />,
    viewAllLabel: "Security settings",
  },
};

const dockItems: DockItem[] = [
  { id: "notifications", icon: Bell, label: "Notifications", badge: 2 },
  { id: "changelog", icon: BookOpen, label: "Changelog" },
  { id: "dashboard", icon: LayoutDashboard, label: "Dashboard" },
  { id: "settings", icon: Settings, label: "Settings" },
  { id: "security", icon: Shield, label: "Security" },
];

// ─── Main Component ───────────────────────────────────────────────────────────

export default function AppleDock02() {
  const [activePanel, setActivePanel] = useState<string | null>(dockItems[0].id);
  const [direction, setDirection] = useState(1);
  const [bodyHeight, setBodyHeight] = useState(0);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const bodyRef = useRef<HTMLDivElement>(null);

  useLayoutEffect(() => {
    if (bodyRef.current) setBodyHeight(bodyRef.current.offsetHeight);
  }, [activePanel]);

  useEffect(() => {
    const handleOutsideClick = (e: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(e.target as Node)) {
        setActivePanel(null);
      }
    };
    document.addEventListener("mousedown", handleOutsideClick);
    return () => document.removeEventListener("mousedown", handleOutsideClick);
  }, []);

  const handleIconClick = (id: string) => {
    if (activePanel === id) { setActivePanel(null); return; }
    const currentIndex = dockItems.findIndex((item) => item.id === activePanel);
    const nextIndex = dockItems.findIndex((item) => item.id === id);
    setDirection(nextIndex > currentIndex ? 1 : -1);
    setActivePanel(id);
  };

  return (
    <div className="flex min-h-105 items-end justify-center bg-background">
      <div ref={wrapperRef} className="relative flex items-center justify-center">

        {/* Floating Panel */}
        <AnimatePresence>
          {activePanel && (
            <motion.div
              key="panel"
              initial={{ opacity: 0, y: 8, scale: 0.97 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: 8, scale: 0.97 }}
              transition={{ type: "spring", stiffness: 400, damping: 30 }}
              className="absolute bottom-full mb-3 w-72 overflow-hidden rounded-2xl border bg-popover shadow-xs"
            >
              {/* Header */}
              <div className="flex items-center justify-between border-b px-4 py-3">
                <AnimatePresence mode="wait" initial={false}>
                  <motion.div
                    key={activePanel + "-title"}
                    initial={{ opacity: 0, y: -4 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: 4 }}
                    transition={{ duration: 0.12 }}
                    className="flex items-center gap-2"
                  >
                    <p className="text-sm font-medium">{panels[activePanel].title}</p>
                    {panels[activePanel].badge && (
                      <Badge variant="secondary" className="h-5 px-1.5 text-xs">
                        {panels[activePanel].badge}
                      </Badge>
                    )}
                  </motion.div>
                </AnimatePresence>
                <Button
                  variant={'ghost'}
                  onClick={() => setActivePanel(null)}
                  className="rounded-full p-1 size-6 cursor-pointer"
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>

              {/* Body */}
              <motion.div
                animate={{ height: bodyHeight }}
                transition={{ type: "spring", stiffness: 300, damping: 30 }}
                className="overflow-hidden"
              >
                <div ref={bodyRef} className="overflow-hidden p-4">
                  <motion.div
                    key={activePanel}
                    custom={direction}
                    initial="hidden"
                    animate="visible"
                    variants={containerVariants}
                  >
                    {panels[activePanel].content}

                    {/* View All Footer */}
                    {panels[activePanel].viewAllLabel && (
                      <PanelItem className="mt-3 border-t border-border pt-3">
                        <a
                          href="#"
                          className="flex items-center justify-between text-xs text-muted-foreground transition-colors hover:text-foreground"
                        >
                          {panels[activePanel].viewAllLabel}
                          <ArrowRight className="h-3 w-3" />
                        </a>
                      </PanelItem>
                    )}
                  </motion.div>
                </div>
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Dock Bar */}
        <div className="flex h-14 w-max items-center justify-center gap-2 rounded-2xl border bg-white/10 p-2 backdrop-blur-md supports-backdrop-filter:bg-white/10 dark:bg-black/10">
          {dockItems.map(({ id, icon: Icon, label, badge }) => (
            <Tooltip key={id}>
              <TooltipTrigger render={
                <div className="relative">
                  <AppleDockIcon
                    isActive={activePanel === id}
                    onClick={() => handleIconClick(id)}
                  >
                    <Icon className="h-5 w-5" />
                  </AppleDockIcon>
                  {badge && (
                    <span className="pointer-events-none absolute -right-0.5 -top-0.5 flex h-4 w-4 items-center justify-center rounded-full bg-red-500 text-[10px] font-medium text-white">
                      {badge}
                    </span>
                  )}
                </div>
              } />
              <TooltipContent side="top" className="text-xs">
                {label}
              </TooltipContent>
            </Tooltip>
          ))}
        </div>
      </div>
    </div>
  );
}
